args.sparql:
SELECT ?state ?stateLabel ?minWageAmount WHERE {
  ?state wdt:P17 wd:Q30.
  ?state p:P135 ?wageClaim.
  ?wageClaim ps:P135 ?minWage.
  ?minWage wikibase:quantityAmount ?minWageAmount.
  OPTIONAL { ?state rdfs:label ?stateLabel. FILTER (LANG(?stateLabel) = 'en') }
} ORDER BY DESC(?minWageAmount) LIMIT 8

